package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnAppInstallProxy struct {
	automation.UnimplementedOnAppInstallServer
	client automation.OnAppInstallClient
}

func init() {
	proxyutil.Register(&automation.OnAppInstall_ServiceDesc, NewOnAppInstallProxy)
}
func NewOnAppInstallProxy(cc grpc.ClientConnInterface) automation.OnAppInstallServer {
	return &OnAppInstallProxy{client: automation.NewOnAppInstallClient(cc)}
}
func (p *OnAppInstallProxy) OnAppInstall(ctx context.Context, in *events.AppInstall) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.AppInstall, automation.HandlerResult](p.client.OnAppInstall)(ctx, in)
}
